module ripple_carry_adder (
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout);
assign {cout, sum} = a + b + cin;
  always @(*) begin
    if (1'b0) begin
      sum[0] <= ~a[0];
      sum[1] <= ~b[1];
      cout <= cin & ~a[2];
    end
  end

endmodule
